import"./hoisted.CY-5tZQz.js";(function(){const s=document.querySelectorAll(".category-btn"),u=document.querySelectorAll(".content-section");function f(t){s.forEach(e=>{const o=e.getAttribute("data-category")===t;e.classList.toggle("active",o),e.setAttribute("aria-selected",o)}),u.forEach(e=>{const o=e.id===t;e.classList.toggle("active",o)})}s.forEach(t=>{t.addEventListener("click",e=>{const o=t.getAttribute("data-category");f(o)})});function d(){document.querySelectorAll("table").forEach(e=>{e.querySelectorAll("tbody tr").forEach(h=>{const l=Array.from(h.querySelectorAll("td:not(:first-child)"));let r=null,n=null;l.forEach(c=>{const i=c.querySelector(".price-value")?.textContent||c.textContent;if(i){const a=parseInt(String(i).replace(/[^0-9]/g,""));isNaN(a)||(r===null||a<r)&&(r=a,n=c)}}),n&&l.length>1&&(n.style.borderLeft="4px solid #00ff88")})})}async function g(){try{const t=await fetch("footer.html");if(t.ok){const e=await t.text();document.getElementById("footer-container").innerHTML=e}}catch(t){console.error("Error loading footer:",t)}}window.showInfo=function(t){alert(`Plus d'informations sur ${t} - Contactez-nous au 0540454907 ou par email à aqa.sports.academy@gmail.com`)},document.addEventListener("DOMContentLoaded",()=>{d(),g()})})();
